const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const triggerData = $('Called by Receiver').first().json;
const issueId = triggerData.issueId || '';
const summary = triggerData.summary || '';

const MAX_SESSION_COST = 5;

const output = stdout.trim() || stderr.trim();

let result, sessionId, isEmpty, costEur = 0, numTurns = 0, durationMs = 0;
try {
  const parsed = JSON.parse(output);
  result = parsed.result || '';
  sessionId = parsed.session_id || '';
  const USD_TO_EUR = 0.92;
  costEur = (parsed.cost_usd || 0) * USD_TO_EUR;
  numTurns = parsed.num_turns || 0;
  durationMs = parsed.duration_ms || 0;
  isEmpty = !result;
} catch (e) {
  // stream-json mode: extract result + cost from JSONL file
  const jsonlPath = '/tmp/claude-run-' + issueId + '.jsonl';
  try {
    const fs = require('fs');
    const lines = fs.readFileSync(jsonlPath, 'utf8').trim().split('\n');

    let lastText = '';
    sessionId = '';
    let totalInputTokens = 0, totalOutputTokens = 0;
    let totalCacheWrite = 0, totalCacheRead = 0;
    numTurns = 0;

    for (const line of lines) {
      try {
        const d = JSON.parse(line);
        if (d.type === 'system' && d.subtype === 'init' && d.session_id) {
          sessionId = d.session_id;
        }
        if (d.type === 'assistant') {
          numTurns++;
          const msg = d.message || {};
          const content = msg.content || [];
          for (const block of content) {
            if (block.type === 'text' && block.text) lastText = block.text;
          }
          const usage = msg.usage || {};
          totalInputTokens += usage.input_tokens || 0;
          totalOutputTokens += usage.output_tokens || 0;
          totalCacheWrite += usage.cache_creation_input_tokens || 0;
          totalCacheRead += usage.cache_read_input_tokens || 0;
        }
      } catch (lineErr) {}
    }

    result = lastText;
    isEmpty = !result;

    // Opus 4.6 pricing (per 1M tokens)
    const costUsd = (totalInputTokens * 15.0 + totalOutputTokens * 75.0 +
                     totalCacheWrite * 18.75 + totalCacheRead * 1.50) / 1000000;
    costEur = costUsd * 0.92;

  } catch (fsErr) {
    if (!output) { result = ''; isEmpty = true; }
    else { result = 'Error: ' + output.substring(0, 1000); isEmpty = false; }
    sessionId = '';
  }
}

const hasValidSession = !!(sessionId && issueId);

const costExceeded = costEur > MAX_SESSION_COST;
if (costExceeded) {
  result = '\u26a0\ufe0f COST CEILING EXCEEDED (\u20ac' + costEur.toFixed(2).replace('.', ',') + ' > \u20ac' + MAX_SESSION_COST + ' limit)\n\n' + result;
}

const confidenceMatch = result.match(/CONFIDENCE:\s*(\d\.\d+|\d)\s*[\u2013\u2014\-]\s*(.+?)(?:\n|$)/i);
const confidence = confidenceMatch ? parseFloat(confidenceMatch[1]) : -1;
const confidenceReason = confidenceMatch ? confidenceMatch[2].trim() : '';
const hasConfidence = confidence >= 0;

const prefix = issueId.split('-')[0] || '';
const isInfra = prefix === 'IFRNLLEI01PRD' || prefix === 'IFRGRSKG01PRD';
const hasApprovalGate = /awaiting approval|waiting for.*approval|reply.*approved|\[POLL\]/i.test(result);
const missingApprovalGate = isInfra && !isEmpty && !hasApprovalGate && result.length > 200;

let inconsistentReasoning = false;
if (hasConfidence && !isEmpty) {
  const hedgingWords = (result.match(/\b(might|possibly|unclear|uncertain|unsure|maybe|perhaps|not sure)\b/gi) || []).length;
  const actionWords = (result.match(/\b(restart|apply|execute|deploy|fix|change|modify|update|remove|delete)\b/gi) || []).length;
  if (confidence >= 0.8 && hedgingWords >= 3) inconsistentReasoning = true;
  if (confidence < 0.5 && actionWords >= 3 && !/\bstop\b.*\bwait\b/i.test(result)) inconsistentReasoning = true;
}

const hasReactStructure = /THOUGHT:|SYNTHESIS:|OBSERVATION:/i.test(result);
const missingReactStructure = isInfra && !isEmpty && result.length > 500 && !hasReactStructure;

const validationWarnings = [];
if (!hasConfidence && !isEmpty && result.length > 100) validationWarnings.push('missing_confidence');
if (missingApprovalGate) validationWarnings.push('missing_approval_gate');
if (inconsistentReasoning) validationWarnings.push('inconsistent_reasoning');
if (missingReactStructure) validationWarnings.push('missing_react_structure');

let promptVariant = '';
try { promptVariant = $('Build Prompt').first().json.promptVariant || ''; } catch(e) {}

return [{ json: {
  result, sessionId, issueId, summary, hasValidSession, isEmpty,
  confidence, confidenceReason, hasConfidence,
  hasApprovalGate, missingApprovalGate,
  inconsistentReasoning, missingReactStructure,
  validationWarnings: validationWarnings.join(','),
  hasWarnings: validationWarnings.length > 0,
  costEur, numTurns, durationMs, costExceeded,
  promptVariant
} }];

const triggerData = $('Called by Receiver').first().json;
const issueId = triggerData.issueId || '';
const summary = triggerData.summary || '';
const description = triggerData.description || 'No description provided.';

const prompt = 'YouTrack issue ' + issueId + ': (continued session)\n\n' + summary + '\n\n' + description + '\n\nProject: /app/cubeos\nMode: gateway — read CLAUDE.md Gateway Mode section before doing anything else.';
const base64Prompt = Buffer.from(prompt).toString('base64');

return [{ json: { issueId, summary, base64Prompt } }];

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const issueId = $('Build Fallback Prompt').first().json.issueId;
const summary = $('Build Fallback Prompt').first().json.summary || '';

const output = stdout.trim() || stderr.trim();

let result, sessionId, costEur = 0, numTurns = 0, durationMs = 0;
try {
  const parsed = JSON.parse(output);
  result = parsed.result || '';
  sessionId = parsed.session_id || '';
  const USD_TO_EUR = 0.92;
  costEur = (parsed.cost_usd || 0) * USD_TO_EUR;
  numTurns = parsed.num_turns || 0;
  durationMs = parsed.duration_ms || 0;
} catch (e) {
  result = '';
  sessionId = '';
}

if (result) {
  result = '(session restarted) ' + result;
} else {
  result = 'Claude did not respond. Type your message again to retry.';
}

const hasValidSession = !!(sessionId && issueId);

return [{ json: { result, sessionId, issueId, summary, hasValidSession, costEur, numTurns, durationMs } }];

const ROOM_MAP = {
  CUBEOS: '!iXTnQsFJahUquYPDdG:matrix.example.net',
  MESHSAT: '!miZJJDwFQZDkuMcBqL:matrix.example.net',
  IFRNLLEI01PRD: '!AOMuEtXGyzGFLgObKN:matrix.example.net',
  IFRGRSKG01PRD: '!NKosBPujbWMevzHaaM:matrix.example.net'
};
const DEFAULT_ROOM = '!PVkZvHgyrtBVEbgpRt:matrix.example.net';
function resolveRoom(issueId) {
  const prefix = (issueId || '').split('-')[0];
  return ROOM_MAP[prefix] || DEFAULT_ROOM;
}
const CREDENTIAL_PATTERNS = [
  /(?:Bearer|Authorization:\s*Bearer)\s+[A-Za-z0-9_.\-]{20,}/gi,
  /perm-[A-Za-z0-9_.=]{10,}/g,
  /ghp_[A-Za-z0-9]{36,}/g,
  /glpat-[A-Za-z0-9\-_]{20,}/g,
  /mct_[A-Za-z0-9_]{20,}/g,
  /n8n_api_[a-f0-9]{20,}/g,
  /sk-[A-Za-z0-9]{20,}/g,
  /-----BEGIN (?:RSA |EC |OPENSSH )?PRIVATE KEY-----/g,
  /AKIA[0-9A-Z]{16}/g,
  /password\s*[:=]\s*['"][^'"]{8,}['"]/gi
];
function scanCredentials(text) {
  const found = [];
  for (const pattern of CREDENTIAL_PATTERNS) {
    pattern.lastIndex = 0;
    const matches = text.match(pattern);
    if (matches) found.push(...matches.map(m => m.substring(0, 15) + '***REDACTED***'));
  }
  return found;
}
function checkHostnames(text) {
  const warnings = [];
  const hostMatches = text.match(/\b(?:nl|gr)[a-z0-9-]+\b/gi) || [];
  for (const host of hostMatches) { if (host.length > 30) warnings.push('Suspicious hostname (too long): ' + host); }
  return warnings;
}
function validateTriageJson(text) {
  const match = text.match(/TRIAGE_JSON:\s*({[^}]+})/);
  if (!match) return null;
  try {
    const triage = JSON.parse(match[1]);
    const missing = ['issueId', 'escalated'].filter(f => !(f in triage));
    if (missing.length > 0) return 'TRIAGE_JSON missing fields: ' + missing.join(', ');
    return null;
  } catch(e) { return 'TRIAGE_JSON malformed: ' + e.message; }
}
function validateReviewJson(text) {
  const match = text.match(/REVIEW_JSON:\s*({[^}]+})/);
  if (!match) return null;
  try {
    const review = JSON.parse(match[1]);
    if (!['AGREE', 'DISAGREE', 'AUGMENT'].includes(review.verdict)) return 'REVIEW_JSON.verdict must be AGREE, DISAGREE, or AUGMENT';
    if (review.confidence !== undefined && (review.confidence < 0 || review.confidence > 1)) return 'REVIEW_JSON.confidence must be 0-1';
    return null;
  } catch(e) { return 'REVIEW_JSON malformed: ' + e.message; }
}
function redactCredentials(text) {
  let r = text;
  for (const p of CREDENTIAL_PATTERNS) { p.lastIndex = 0; r = r.replace(p, '[CREDENTIAL REDACTED]'); }
  return r;
}
function applyInline(text) {
  return text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\*\*\*(.+?)\*\*\*/g,'<strong><em>$1</em></strong>').replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/\*(.+?)\*/g,'<em>$1</em>').replace(/(?<!\w)_([^_]+)_(?!\w)/g,'<em>$1</em>').replace(/`([^`]+)`/g,'<code>$1</code>').replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<a href="$2">$1</a>');
}
function markdownToHtml(md) {
  if (!md) return '';
  const lines = md.split('\n');
  const out = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    if (line.trimStart().startsWith('```')) {
      const cl = [line]; i++;
      while (i < lines.length && !lines[i].trimStart().startsWith('```')) { cl.push(lines[i]); i++; }
      if (i < lines.length) { cl.push(lines[i]); i++; }
      const c = cl.slice(1,-1).join('\n').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
      out.push('<pre><code>' + c + '</code></pre>'); continue;
    }
    if (/^\|.+\|$/.test(line.trim())) {
      const tl = [];
      while (i < lines.length && /^\|.+\|$/.test(lines[i].trim())) { tl.push(lines[i].trim()); i++; }
      const rows = tl.filter(l => !/^\|[\s|:-]+\|$/.test(l));
      if (rows.length === 0) continue;
      const pr = (row) => row.split('|').slice(1,-1).map(c => c.trim());
      const hc = pr(rows[0]);
      const thead = '<thead><tr>' + hc.map(c => '<th>' + applyInline(c) + '</th>').join('') + '</tr></thead>';
      const tbody = rows.length > 1 ? '<tbody>' + rows.slice(1).map(row => '<tr>' + pr(row).map(c => '<td>' + applyInline(c) + '</td>').join('') + '</tr>').join('') + '</tbody>' : '';
      out.push('<table>' + thead + tbody + '</table>'); continue;
    }
    if (/^[-*+] /.test(line)) {
      const li = []; while (i < lines.length && /^[-*+] /.test(lines[i])) { li.push(lines[i].replace(/^[-*+] /,'')); i++; }
      out.push('<ul>' + li.map(x => '<li>' + applyInline(x) + '</li>').join('') + '</ul>'); continue;
    }
    if (/^\d+\. /.test(line)) {
      const li = []; while (i < lines.length && /^\d+\. /.test(lines[i])) { li.push(lines[i].replace(/^\d+\. /,'')); i++; }
      out.push('<ol>' + li.map(x => '<li>' + applyInline(x) + '</li>').join('') + '</ol>'); continue;
    }
    const h3 = line.match(/^### (.+)$/); if (h3) { out.push('<h3>' + applyInline(h3[1]) + '</h3>'); i++; continue; }
    const h2 = line.match(/^## (.+)$/); if (h2) { out.push('<h2>' + applyInline(h2[1]) + '</h2>'); i++; continue; }
    const h1 = line.match(/^# (.+)$/); if (h1) { out.push('<h1>' + applyInline(h1[1]) + '</h1>'); i++; continue; }
    if (/^---+$/.test(line.trim())) { out.push('<hr>'); i++; continue; }
    out.push(applyInline(line)); i++;
  }
  let html = out.join('\n').replace(/\n\n+/g,'</p><p>').replace(/\n/g,'<br>');
  if (!html.match(/^<(p|h[1-6]|ul|ol|pre|table|hr)/)) html = '<p>' + html + '</p>';
  return html;
}
function smartTruncate(text, maxLen) {
  if (text.length <= maxLen) return text;
  const confMatch = text.match(/CONFIDENCE:\s*\d\.\d+.*$/m);
  const approvalMatch = text.match(/(Awaiting approval|waiting for.*approval).*$/im);
  const planMatch = text.match(/(## (?:Proposed Actions|Remediation Plan|Plan|Proposed Fix)\s*\n[\s\S]*?)(?=\nCONFIDENCE:|\n## (?!Proposed|Remediation|Plan)|$)/im);
  const preserved = [];
  if (planMatch) preserved.push(planMatch[1].trim());
  if (confMatch) preserved.push(confMatch[0]);
  if (approvalMatch && (!confMatch || approvalMatch[0] !== confMatch[0])) preserved.push(approvalMatch[0]);
  if (preserved.length > 0) {
    const suffix = '\n\n' + preserved.join('\n');
    const mainLen = maxLen - suffix.length - 20;
    if (mainLen > 500) return text.substring(0, mainLen) + '\n\n[...truncated...]' + suffix;
  }
  return text.substring(0, maxLen - 15) + '\n\n[...truncated]';
}
function parsePoll(result) {
  const pollMatch = result.match(/\[POLL\]\s*(.+?)\n([\s\S]+)$/m);
  if (!pollMatch) {
    // Fallback: detect plan-style responses without literal [POLL]
    const planMatch = result.match(/(?:Which approach|Which plan|Which option|Which remediation).*\?\s*\n((?:\s*-\s+Plan\s+[A-Z]:.+\n?){2,})/im);
    if (planMatch) {
      const question = result.match(/(Which.+\?)/i)?.[1] || 'Which approach do you prefer?';
      const options = planMatch[1].split('\n').map(l => l.trim()).filter(l => /^-\s+/.test(l)).map(l => l.replace(/^-\s+/, '').trim());
      if (options.length >= 2) {
        const contextEnd = result.indexOf(planMatch[0]);
        return { question, options: options.map((opt, i) => ({ id: 'opt' + i, 'org.matrix.msc1767.text': opt })), context: result.substring(0, contextEnd).trim() };
      }
    }
    return null;
  }
  const question = pollMatch[1].trim();
  const optionLines = pollMatch[2].trim().split('\n').map(l => l.replace(/^[-*+]\s*/,'').trim()).filter(l => l.length > 0 && !l.startsWith('CONFIDENCE:') && !l.match(/^\s*$/));
  if (optionLines.length < 2) return null;
  const answers = optionLines.map((opt, i) => ({ id: 'opt' + i, 'org.matrix.msc1767.text': opt }));
  const contextEnd = result.indexOf('[POLL]');
  const context = contextEnd > 0 ? result.substring(0, contextEnd).trim() : '';
  return { question, answers, context };
}

const data = $input.first().json;
const issueId = data.issueId || '';
let result = data.result || 'No response';
const sessionId = data.sessionId || '';
const summary = data.summary || '';
const hasValidSession = data.hasValidSession || false;
const targetRoom = resolveRoom(issueId);
const retriedWithWarnings = data.retriedWithWarnings || false;
const retryCount = data.retryCount || 0;
const costEur = data.costEur || 0;
const numTurns = data.numTurns || 0;
const confidence = data.confidence !== undefined ? data.confidence : -1;
const durationMs = data.durationMs || 0;

const credentialsFound = scanCredentials(result);
let guardrailBanner = '';
if (credentialsFound.length > 0) {
  result = redactCredentials(result);
  guardrailBanner = '\u26d4 GUARDRAIL: ' + credentialsFound.length + ' credential(s) redacted from response\n\n';
}

let durationSeconds = 0;
if (durationMs > 0) {
  durationSeconds = Math.round(durationMs / 1000);
} else {
  try {
    const preStart = $('Format Pre Stats').first().json.preStartTime;
    if (preStart) durationSeconds = Math.round((Date.now() - preStart) / 1000);
  } catch(e) {}
}

let runtimeTag = '';
if (durationSeconds > 0) {
  const mins = Math.floor(durationSeconds / 60);
  const remSecs = durationSeconds % 60;
  runtimeTag = mins > 0 ? ' (' + mins + 'm' + remSecs + 's)' : ' (' + durationSeconds + 's)';
}

let promptVariant = '';
let alertCategory = '';
try { promptVariant = $('Parse Response').first().json.promptVariant || ''; } catch(e) {}
try { alertCategory = $('Build Prompt').first().json.alertCategory || ''; } catch(e) {}

const poll = parsePoll(result);
let matrixBody;
let matrixEventType = 'm.room.message';

if (poll) {
  const contextPlain = poll.context ? '[' + issueId + '] Claude' + runtimeTag + ':\n\n' + poll.context.substring(0, 4000) : '';
  const contextHtml = poll.context ? '<p><strong>[' + issueId + '] Claude' + runtimeTag + ':</strong></p>' + markdownToHtml(poll.context.substring(0, 4000)) : '';
  const fallbackText = '[' + issueId + '] ' + poll.question + '\n' + poll.answers.map((a, i) => (i+1) + '. ' + a['org.matrix.msc1767.text']).join('\n');
  matrixBody = JSON.stringify({
    'org.matrix.msc1767.text': fallbackText,
    'org.matrix.msc3381.poll.start': {
      kind: 'org.matrix.msc3381.poll.disclosed',
      max_selections: 1,
      question: { 'org.matrix.msc1767.text': '[' + issueId + '] ' + poll.question },
      answers: poll.answers
    }
  });
  matrixEventType = 'org.matrix.msc3381.poll.start';
  return [{ json: { issueId, sessionId, summary, hasValidSession, matrixBody, targetRoom, matrixEventType, contextBody: contextPlain ? JSON.stringify({ msgtype: 'm.text', body: contextPlain, format: 'org.matrix.custom.html', formatted_body: contextHtml }) : '', costEur, numTurns, durationSeconds, confidence, promptVariant, alertCategory } }];
}

const hostnameWarnings = checkHostnames(result);
const triageError = validateTriageJson(result);
const reviewError = validateReviewJson(result);
let factCheckBanner = '';
if (hostnameWarnings.length > 0 || triageError || reviewError) {
  const issues = [...hostnameWarnings];
  if (triageError) issues.push(triageError);
  if (reviewError) issues.push(reviewError);
  factCheckBanner = '\u26a0\ufe0f FACT-CHECK: ' + issues.join('; ') + '\n\n';
}

const needsApproval = /approv|waiting|human|confirm/i.test(result);
const mentionPill = needsApproval ? '<a href="https://matrix.to/#/@dominicus:matrix.example.net">@dominicus</a> ' : '';
const mentionPlain = needsApproval ? '@dominicus ' : '';

const validationBanner = retriedWithWarnings ? '\u26a0\ufe0f VALIDATION INCOMPLETE \u2014 missing required fields after ' + retryCount + ' retries\n\n' : '';
const validationHtml = retriedWithWarnings ? '<p><strong>\u26a0\ufe0f VALIDATION INCOMPLETE</strong> \u2014 missing required confidence score or approval gate after ' + retryCount + ' retries</p>' : '';
const truncated = smartTruncate(result, 6000);

const costTag = costEur > 0 ? ' | \u20ac' + costEur.toFixed(2).replace('.', ',') : '';
const plainText = mentionPlain + guardrailBanner + factCheckBanner + validationBanner + '[' + issueId + '] Claude' + runtimeTag + costTag + ':\n\n' + truncated;
const htmlText = mentionPill + (factCheckBanner ? '<p><strong>\u26a0\ufe0f FACT-CHECK:</strong> Output validation warnings detected</p>' : '') + (guardrailBanner ? '<p><strong>\u26d4 GUARDRAIL:</strong> ' + credentialsFound.length + ' credential(s) redacted from response</p>' : '') + validationHtml + '<p><strong>[' + issueId + '] Claude' + runtimeTag + costTag + ':</strong></p>' + markdownToHtml(truncated);

matrixBody = JSON.stringify({
  msgtype: 'm.text',
  body: plainText,
  format: 'org.matrix.custom.html',
  formatted_body: htmlText
});

return [{ json: { issueId, sessionId, summary, hasValidSession, matrixBody, targetRoom, matrixEventType: 'm.room.message', contextBody: '', retriedWithWarnings, retryCount, costEur, numTurns, durationSeconds, confidence, promptVariant, alertCategory } }];

const ROOM_MAP = {
  CUBEOS: '!iXTnQsFJahUquYPDdG:matrix.example.net',
  MESHSAT: '!miZJJDwFQZDkuMcBqL:matrix.example.net',
  IFRNLLEI01PRD: '!AOMuEtXGyzGFLgObKN:matrix.example.net', IFRGRSKG01PRD: '!NKosBPujbWMevzHaaM:matrix.example.net'
};
const DEFAULT_ROOM = '!PVkZvHgyrtBVEbgpRt:matrix.example.net';

const stdout = $('Check Cooldown').first().json.stdout || '';
const parts = stdout.trim().split(':');
const issueId = parts[1] || '?';
const remain = parts[2] || '?';
const prefix = (issueId || '').split('-')[0];
const targetRoom = ROOM_MAP[prefix] || DEFAULT_ROOM;
const body = '\u26a0 Session start for ' + issueId + ' blocked by cooldown (retry in ' + remain + 's)';
const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, targetRoom } }];

const stdout = $('Gather Pre Stats').first().json.stdout || '';
const lines = stdout.split('\n');
const vals = {};
lines.forEach(l => { const i = l.indexOf(':'); if (i > 0) vals[l.substring(0, i)] = l.substring(i + 1).trim(); });
const ROOMS = { CUBEOS: '!iXTnQsFJahUquYPDdG:matrix.example.net', MESHSAT: '!miZJJDwFQZDkuMcBqL:matrix.example.net', IFRNLLEI01PRD: '!AOMuEtXGyzGFLgObKN:matrix.example.net', IFRGRSKG01PRD: '!NKosBPujbWMevzHaaM:matrix.example.net' };
const issueId = $('Called by Receiver').first().json.issueId || '';
const targetRoom = ROOMS[issueId.split('-')[0]] || '!PVkZvHgyrtBVEbgpRt:matrix.example.net';

const memParts = (vals.MEM_CG || '0:max').split(':');
const memCurMiB = Math.round(parseInt(memParts[0] || '0') / 1048576);
const memMaxRaw = memParts[1] || 'max';
const memStr = memMaxRaw === 'max' ? memCurMiB + ' MiB (no limit)' : memCurMiB + '/' + Math.round(parseInt(memMaxRaw) / 1048576) + ' MiB';

const psiMatch = (vals.CPU_PSI || '').match(/avg10=([\d.]+)\s+avg60=([\d.]+)\s+avg300=([\d.]+)/);
const cpuStr = psiMatch ? 'PSI ' + psiMatch[1] + '/' + psiMatch[2] + '/' + psiMatch[3] + '%' : '?';

const nproc = vals.NPROC || '?';

let gpu = 'unreachable';
if (vals.GPU && vals.GPU !== 'unreachable') { const p = vals.GPU.split(',').map(s => s.trim()); if (p.length >= 3) gpu = p[0] + '%, ' + p[1] + '/' + p[2] + ' MiB'; }

const body = 'Starting session for ' + issueId + '\nCPU: ' + cpuStr + ' (' + nproc + ' cores) | Mem: ' + memStr + ' | GPU: ' + gpu;
return [{ json: { matrixBody: JSON.stringify({ msgtype: 'm.notice', body }), targetRoom, preStartTime: Date.now() } }];

const ALERTS_ROOM = '!xeNxtpScJWCmaFjeCL:matrix.example.net';
const stdout = $('Gather Pre Stats').first().json.stdout || '';
const lines = stdout.split('\n');
const vals = {};
lines.forEach(l => { const i = l.indexOf(':'); if (i > 0) vals[l.substring(0, i)] = l.substring(i + 1).trim(); });

const alerts = [];
const issueId = $('Called by Receiver').first().json.issueId || '?';

// GPU alerts
if (vals.GPU === 'unreachable') alerts.push('GPU unreachable on gpu01');
if (vals.GPU && vals.GPU !== 'unreachable') {
